map "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/StepCountQuestionnaireResponseToObservation" = "StepCountQuestionnaireResponseToObservation"

/// url = "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/StepCountQuestionnaireResponseToObservation"
/// name = "StepCountQuestionnaireResponseToObservation"
/// title = "Step Count Q to O"
/// status = "active"

uses "http://hl7.org/fhir/StructureDefinition/QuestionnaireResponse" alias QR as source
uses "http://hl7.org/fhir/StructureDefinition/Observation" alias Obs as target
uses "http://hl7.org/fhir/StructureDefinition/Quantity" alias Quantity as source

imports "http://hl7.org/fhir/StructureMap/*"
imports "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/QuestionnaireResponseToObservationBase"

group StepCountQuestionnaireResponseToObservation(source src : QR, target tgt : Obs) {
  src then SetObservationBase(src, tgt) "Base";
  src -> tgt.meta = create('Meta') as meta,
    meta.profile = 'https://fhir.hl7.at/prenudge/appdata/r4/StructureDefinition/at-prenudge-stepcount-observation' "SetProfile";
  src -> tgt.code = cc('http://loinc.org', '41950-7', 'Number of steps in 24 hour Measured') "SetCode";
  
  // Quantity step count entry
  src.item as item where linkId = 'step-count' then MapStepCount(item, tgt) "ProcessQuantityStepCount";
  
  // EHIS-PAQ walking survey
  // src.item as item where linkId = 'Q2-walking-days' then MapEhisPaqToStepCount(item, tgt) "ProcessEhisPaq";
}

// Direct step count mapping
group MapStepCount(source src : QR, target tgt : Obs) {
  src.answer as answer then {
    // effectiveDateTime from nested item with linkId = 'date'
    answer.item as dtItem where linkId = 'date' then {
      dtItem.answer as dtAns then {
        dtAns.valueDate as dt -> tgt.effectiveDateTime = dt "SetEffectiveFromDate";
      } "ExtractDate";
    } "ProcessDate";

    answer.valueQuantity as srcQty then MapStepCountQuantity(srcQty, tgt) "MapValueQuantity";

    // TODO: Note mapping disabled due to MaLaC-HD bug - copy markdown fails with None source type
    // See: https://gitlab.com/cdehealth/malac-hd/-/issues/128

    // Map comment to note
    // answer.item as commentItem where linkId = 'comment' then {
    //   commentItem.answer as commentAnswer then {
    //     commentAnswer.valueString as commentText then {
    //       commentText.value as tv -> tgt.note as note, note.text = tv "SetNoteText";
    //     } "ExtractText";
    //   } "ProcessCommentAnswer";
    // } "ProcessComment";

  } "ProcessAnswer";
}

group MapStepCountQuantity(source srcQty : Quantity, target tgt : Obs) {
  srcQty.value as v -> tgt.value = create('Quantity') as qty then {
    v.value as numVal -> qty.value = numVal "SetValue";
    srcQty -> qty.unit = '{steps}/d' "SetUnit";
    srcQty -> qty.system = 'http://unitsofmeasure.org' "SetSystem";
    srcQty -> qty.code = '{steps}/d' "SetCode";
  } "MapQuantityValue";
}

